```cpp
#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  struct Student {
    std::string SNo;                    // varchar(10) NOT NULL PRIMARY KEY
    std::string SName;                  // varchar(30) NOT NULL
    std::optional<int> Sex;             // int NULL DEFAULT 1
    std::optional<std::string> Birthday;// datetime NULL
    std::optional<int> Major;           // int NULL
    std::optional<float> Scorses;       // float NULL DEFAULT 0
    std::optional<std::string> Remark;  // text NULL
  };

  struct Course {
    sqlgen::PrimaryKey<int> CID;        // int NOT NULL auto_increment PK
    std::string CName;                  // varchar(30) NOT NULL
    std::optional<int> Term;            // int NULL DEFAULT 1
    std::optional<int> CTime;           // int NULL
    float Credit;                       // float NOT NULL DEFAULT 0
  };

  struct Score {
    std::string SNo;                    // varchar(10) NOT NULL (FK)
    int CID;                            // int NOT NULL (FK)
    std::optional<float> Score;         // float NULL
  };

  void design_eas_database() {
    // Remove existing database if it exists
    if (std::filesystem::exists("test_db.sqlite")) {
      std::filesystem::remove("test_db.sqlite");
    }

    // Connect to SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Create Student table with custom schema
    db.run(R"(
      CREATE TABLE IF NOT EXISTS Student (
        SNo VARCHAR(10) NOT NULL PRIMARY KEY,
        SName VARCHAR(30) NOT NULL,
        Sex INTEGER DEFAULT 1,
        Birthday DATETIME,
        Major INTEGER,
        Scorses REAL DEFAULT 0,
        Remark TEXT
      )
    )");

    // Create Course table with auto-increment primary key
    db.run(R"(
      CREATE TABLE IF NOT EXISTS Course (
        CID INTEGER PRIMARY KEY AUTOINCREMENT,
        CName VARCHAR(30) NOT NULL,
        Term INTEGER DEFAULT 1,
        CTime INTEGER,
        Credit REAL NOT NULL DEFAULT 0
      )
    )");

    // Create Score table with composite primary key and foreign keys
    db.run(R"(
      CREATE TABLE IF NOT EXISTS Score (
        SNo VARCHAR(10) NOT NULL,
        CID INTEGER NOT NULL,
        Score REAL,
        PRIMARY KEY (SNo, CID),
        FOREIGN KEY (SNo) REFERENCES Student(SNo),
        FOREIGN KEY (CID) REFERENCES Course(CID)
      )
    )");
  }

}
