#include <vector>

namespace query_employee_hierarchy {

struct Employee {
  sqlgen::PrimaryKey<int> emp_id;
  std::string name;
  std::optional<int> manager_id;
};

struct EmployeeManager {
  std::string employee;
  std::optional<std::string> manager;
};

std::vector<EmployeeManager> query_employee_hierarchy() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto db = sqlite::Database("test_db.sqlite");

    // Execute self-join query
    // LEFT JOIN ensures employees without managers (null manager_id) are included
    auto result = db.query<EmployeeManager>(
        R"(SELECT e1.name as employee, e2.name as manager 
           FROM Employee e1 
           LEFT JOIN Employee e2 ON e1.manager_id = e2.emp_id)"
    );

    return result;
}

}  // namespace query_employee_hierarchy
```

This implementation:

1. **Connects to the SQLite database** using `sqlite::Database("test_db.sqlite")`

2. **Performs a self-join** by aliasing the Employee table twice (e1 for employees, e2 for managers)

3. **Uses LEFT JOIN** to include employees without managers - when `manager_id` is NULL, the join will still include the employee row with a NULL manager

4. **Maps the results** to the `EmployeeManager` struct:
   - `e1.name` → `employee` field
   - `e2.name` → `manager` field (as `std::optional<std::string>` to handle NULLs)

5. **Returns the vector** of `EmployeeManager` objects containing all employee-manager relationships

