  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to database and ensure table exists
    auto db_result = sqlgen::sqlite::connect("test_db.sqlite")
        .and_then(create_table<Book> | if_not_exists)
        .and_then(sqlgen::read<std::vector<Book>>);

    // Handle connection/read errors
    if (!db_result) {
        return {};
    }

    auto all_books = db_result.value();
    std::vector<Book> filtered_books;

    // Apply filters dynamically
    for (const auto& book : all_books) {
        bool matches = true;

        // Filter by title keyword (LIKE operation)
        if (filters.title_keyword.has_value()) {
            if (book.title.find(filters.title_keyword.value()) == std::string::npos) {
                matches = false;
            }
        }

        // Filter by minimum year (>= operation)
        if (filters.min_year.has_value()) {
            if (book.year < filters.min_year.value()) {
                matches = false;
            }
        }

        // Filter by genre (= operation)
        if (filters.genre.has_value()) {
            if (book.genre != filters.genre.value()) {
                matches = false;
            }
        }

        // Filter by maximum price (<= operation)
        if (filters.max_price.has_value()) {
            if (book.price > filters.max_price.value()) {
                matches = false;
            }
        }

        if (matches) {
            filtered_books.push_back(book);
        }
    }

    return filtered_books;
}

}  // namespace query_search_books_by_criteria
