  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  try {
    // Begin transaction
    auto begin_result = conn.and_then([](auto db) {
      return db.execute("BEGIN TRANSACTION");
    });

    if (!begin_result) {
      return false;
