        update<Account>()
          .set("balance"_c = "balance"_c - amount)
          .where("account_id"_c == from_account_id && "balance"_c >= amount)
      );
    });

    // Check if deduction was successful (row was affected)
    if (!deduct_result || deduct_result->rows_affected() == 0) {
      conn.and_then([](auto db) { return db.execute("ROLLBACK"); });
      return false;
