```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // SQLite doesn't support RIGHT JOIN natively, so we simulate it with LEFT JOIN
  // To include all departments (even those without projects):
  // Department LEFT JOIN Project
  // However, based on the DepProj struct where department_name is optional
  // and project_name is required, this appears to want all projects.

  // Connect to the database and execute the query
  auto conn = sqlite::connect("test_db.sqlite");

  // Since SQLite doesn't support RIGHT JOIN, we use LEFT JOIN with swapped tables
  // This simulates: Projects RIGHT JOIN Departments (to get all departments)
  // We do: Departments LEFT JOIN Projects
  auto result = conn.and_then(
    sqlgen::execute<std::vector<DepProj>>(
      R"(SELECT d.name as department_name, p.name as project_name 
         FROM Department d 
         LEFT JOIN Project p ON d.department_id = p.department_id)"
    )
  );

  return result.value_or(std::vector<DepProj>{});
}

}  // namespace right_join_departments_projects
```

**Note:** Since SQLite doesn't natively support `RIGHT JOIN`, this implementation simulates it using a `LEFT JOIN` with the tables in the appropriate order. The query `Department LEFT JOIN Project` includes all departments (even those without associated projects), which is equivalent to `Project RIGHT JOIN Department` in databases that support RIGHT JOIN.

The function:
1. Connects to "test_db.sqlite"
2. Executes a LEFT JOIN query that includes all departments
3. Returns the results as a vector of DepProj structs
4. Returns an empty vector if the operation fails

