};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a complex query with where, order_by, and limit
  // Note: This demonstrates dry-run SQL generation
  // Querying table B with conditions on score and a_id (representing the join relationship)
  const auto query = sqlgen::read<std::vector<B>> |
                     where("score"_c > 10.0 and "a_id"_c > 0) |
                     order_by("score"_c) |
                     limit(10);

  // Use to_sql to generate SQL string without execution (dry run)
  // This returns the SQL string for debugging without executing against the database
  std::string sql = sqlgen::sqlite::to_sql(query);

  return sql;
}

}  // namespace generate_sql_dry_run
