    Account{.account_id = 3, .balance = 300.0, .status = "inactive"}
  };

  result = result.and_then(write(accounts));
  if (!result) return false;

  // Step 3: Update balances and statuses using set(...)
  // Update account 1: set both balance and status
  result = result.and_then(
