```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;

  // SQLite doesn't support FULL OUTER JOIN natively
  // We simulate it using UNION of LEFT JOIN and products without suppliers
  const std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION
    SELECT '' as supplier_name, p.name as product_name
    FROM Product p
    WHERE p.supplier_id NOT IN (SELECT supplier_id FROM Supplier)
  )";

  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(sqlgen::execute<std::vector<SupProd>>(query));

  return result.value_or(std::vector<SupProd>{});
}

}  // namespace full_join_suppliers_products
```

This implementation:

1. **Connects to the specified database**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to connect to the SQLite database file.

2. **Simulates FULL JOIN**: Since SQLite doesn't support FULL OUTER JOIN natively, it uses a UNION of:
   - A LEFT JOIN to get all suppliers with their products (if any)
   - A query to get products that don't have a matching supplier (using WHERE NOT IN)

3. **Returns all rows**: The result includes:
   - All suppliers with their products (product_name filled)
   - Suppliers without products (product_name as NULL/nullopt)
   - Products without suppliers (supplier_name as empty string, product_name filled)

4. **Handles errors gracefully**: Returns an empty vector if the connection or query fails using `value_or()`.

