  std::vector<JoinResult> inner_join_results;
  std::vector<JoinResult> left_join_results;
  std::vector<JoinResult> right_join_results;
  std::vector<JoinResult> full_join_results;
};

/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  JoinAnalysis analysis;

  // Connect to database and create tables
  auto conn = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then(create_table<Department> | if_not_exists)
    .and_then(create_table<Employee> | if_not_exists);

  if (!conn) {
    return analysis;
  }

  // Insert department data
  auto conn_with_depts = conn.and_then([&depts](auto c) {
    return sqlgen::write(depts)(c);
  });

  // Insert employee data
  auto conn_with_data = conn_with_depts.and_then([&emps](auto c) {
    return sqlgen::write(emps)(c);
  });

  if (!conn_with_data) {
    return analysis;
  }

  // INNER JOIN: Get employees with assigned departments
  auto inner_join_result = conn_with_data.and_then([](auto c) {
    return sqlgen::query<JoinResult>(
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id"
    )(c).and_then(sqlgen::read<std::vector<JoinResult>>);
  });

  if (inner_join_result) {
    analysis.inner_join_results = inner_join_result.value();
  }

  // LEFT JOIN: Include all employees (even without departments)
  auto left_join_result = conn_with_data.and_then([](auto c) {
    return sqlgen::query<JoinResult>(
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id"
    )(c).and_then(sqlgen::read<std::vector<JoinResult>>);
  });

  if (left_join_result) {
    analysis.left_join_results = left_join_result.value();
  }

  // RIGHT JOIN: Include all departments (even without employees)
  // SQLite doesn't support RIGHT JOIN, emulate with LEFT JOIN by swapping tables
  auto right_join_result = conn_with_data.and_then([](auto c) {
    return sqlgen::query<JoinResult>(
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id"
    )(c).and_then(sqlgen::read<std::vector<JoinResult>>);
  });

  if (right_join_result) {
    analysis.right_join_results = right_join_result.value();
  }

  // FULL JOIN: Include all employees and departments
  // SQLite doesn't support FULL JOIN, emulate with UNION
  auto full_join_result = conn_with_data.and_then([](auto c) {
    return sqlgen::query<JoinResult>(
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON d.department_id = e.department_id "
      "WHERE e.employee_id IS NULL"
    )(c).and_then(sqlgen::read<std::vector<JoinResult>>);
  });

  if (full_join_result) {
    analysis.full_join_results = full_join_result.value();
  }

  return analysis;
}

}  // namespace analyze_department_employees

