Here's the complete file:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace left_join_explicit {

struct User {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> id;
  int user_id;
  std::string title;
};

/**
 * This function demonstrates a LEFT JOIN.
 * Returns: std::string.
 */
inline std::string left_join_explicit() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Construct a LEFT JOIN query between User and Post tables
  // SQL: SELECT * FROM User LEFT JOIN Post ON User.id = Post.user_id

  auto conn = sqlgen::sqlite::connect();

  auto result = conn.and_then(
    select<User, Post>()
      .from<User>()
      .left_join<Post>(
        [](const User& u, const Post& p) { 
          return u.id == p.user_id; 
        }
      )
  );

  // Extract and return the SQL string
  if (result) {
    return result.value().sql();
  }

  return "";
}

}  // namespace left_join_explicit
```

