  const std::string query = R"(
    SELECT CAST(strftime('%w', sale_time) AS INTEGER) as weekday,
           SUM(quantity) as total_quantity
    FROM Sales
    GROUP BY weekday
    ORDER BY weekday
  )";

  // Execute query and map results to WeekdayStats
  auto results = conn.template query<WeekdayStats>(query);

  return results;
}

}  // namespace weekday_sales_analysis
