```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including day, month, year, hour, minute, second, and duration in days.
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to the SQLite database
  auto db = sqlite::connect({.path = "test_db.sqlite"});

  // Execute query with JOIN and SQLite-specific date/time operations
  // SQLite uses strftime() for extracting date/time components
  // and julianday() for calculating date differences
  const auto query = R"(
    SELECT p.project_id, p.name,
           CAST(strftime('%d', t.start_time) AS INTEGER) as day,
           CAST(strftime('%m', t.start_time) AS INTEGER) as month,
           CAST(strftime('%Y', t.start_time) AS INTEGER) as year,
           CAST(strftime('%H', t.start_time) AS INTEGER) as hour,
           CAST(strftime('%M', t.start_time) AS INTEGER) as minute,
           CAST(strftime('%S', t.start_time) AS INTEGER) as second,
           (julianday(t.end_time) - julianday(t.start_time)) as duration_days
    FROM Project p
    INNER JOIN TimeLog t ON p.project_id = t.project_id
  )";

  return db.template query<TimeMetrics>(query);
}

}  // namespace project_time_tracking
```

**Key Implementation Details:**

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` with the path to "test_db.sqlite"

2. **SQLite Date/Time Functions**: Since SQLite doesn't have `DAY()`, `MONTH()`, `YEAR()`, etc. functions like MySQL, I used SQLite's `strftime()` function:
   - `strftime('%d', timestamp)` - extracts day
   - `strftime('%m', timestamp)` - extracts month
   - `strftime('%Y', timestamp)` - extracts year
   - `strftime('%H', timestamp)` - extracts hour
   - `strftime('%M', timestamp)` - extracts minute
   - `strftime('%S', timestamp)` - extracts second

3. **Days Between Calculation**: Uses `julianday()` function to convert timestamps to Julian day numbers and calculates the difference (equivalent to `DAYS_BETWEEN()` in other databases)

4. **Type Casting**: Casts `strftime()` results to `INTEGER` to match the expected int types in the `TimeMetrics` struct

5. **JOIN Operation**: Performs an INNER JOIN between Project and TimeLog tables on the project_id field

6. **Return Type**: The query is executed with the `TimeMetrics` struct as the template parameter, which automatically maps the query results to the struct fields

